import numpy as np
from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector, Pauli

def z_expectation(build):
    qc = QuantumCircuit(1)
    build(qc)
    sv = Statevector.from_instruction(qc)
    return round(float(np.real(sv.expectation_value(Pauli("Z")))), 4)

builds = {
    "A": lambda qc: qc.h(0),
    "B": lambda qc: qc.x(0),
    "C": lambda qc: qc.ry(np.pi / 3, 0),
    "D": lambda qc: (qc.h(0), qc.s(0)),
    "E": lambda qc: None,
}
evidence = {}
proven = []
z_by_opt = {}
for k, b in builds.items():
    z = z_expectation(b)
    z_by_opt[k] = z
    on_equator = abs(z) < 1e-9
    evidence[k] = f"<Z> = {z} -> on equator (|<Z>|~0) = {on_equator}"
    if on_equator:
        proven.append(k)

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"z_expectation_by_option": z_by_opt},
})
